SELECT UTLINSTT_ID , RCMD_ENPR_BZN , RCMD_ID , PRN_NM , CHRG_AUDOFIR , CNPL , EAD , RCMD_ENPR_NM , MAIN_BIZ , LEAD_INVSTR_PRN_NM , LEAD_INVSTR_AMOUNT , LEAD_INVSTR_STEP , INVM_RND_END_PNTTM , TOT_INVM_CNFMN_AMT , TOT_INVM_CNFMN_AMT_TO , PROGRS_VALUE , PROGRS_VALUE_TO , RECOMEND_OPINION , OPRTR_CNFA_YN , ATCHMNFL , SBMS_STTS , RGSN_TS , RGSN_USER_ID , AMNN_TS , AMNN_USER_ID FROM TB_BOX_IVT_RECOMENDCP_INFO_BASS_M WHERE UTLINSTT_ID = #{userGroupId}
AND RCMD_ENPR_NM LIKE '%' || #{cmpnNm} || '%'
AND RCMD_ENPR_BZN = #{bizNum}
ORDER BY RGSN_TS DESC

mapper.update:
UPDATE
TB_BOX_IVT_RECOMENDCP_INFO_BASS_M
SET
SBMS_STTS = 'N'
, AMNN_USER_ID = #{amnnUserId}
, AMNN_TS = CURRENT_TIMESTAMP
WHERE UTLINSTT_ID = #{utlinsttId}
AND RCMD_ID = #{rcmdId}

